const SELECT_OPEN_BAR_PLACEHOLDER = "Select Open Bar";

type OpenBarMode = "default" | "pubCrawl" | "bottomlessBrunch";

const NIGHT_REPORT_FILE_PREFIX = "night_report";
const FALLBACK_PRODUCT_SEGMENT = "general";

const sanitizeProductSegment = (name: string | null | undefined): string => {
  if (!name) {
    return FALLBACK_PRODUCT_SEGMENT;
  }
  const normalized = name
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
  return normalized || FALLBACK_PRODUCT_SEGMENT;
};

const extractFileExtension = (fileName: string): string | null => {
  const match = /\.([a-zA-Z0-9]+)$/.exec(fileName);
  return match ? match[1].toLowerCase() : null;
};

const buildNightReportPhotoFileName = (
  activityDate: string | null | undefined,
  productName: string | null | undefined,
  originalName: string,
): string => {
  const parsedDate = activityDate ? dayjs(activityDate) : dayjs();
  const dateSegment = parsedDate.isValid() ? parsedDate.format("YYYYMMDD") : dayjs().format("YYYYMMDD");
  const productSegment = sanitizeProductSegment(productName);
  const extension = extractFileExtension(originalName) ?? "jpg";
  const base = `${NIGHT_REPORT_FILE_PREFIX}_${dateSegment}_${productSegment}`;
  return `${base}.${extension}`;
};

const isPreviewableInvoiceMimeType = (mimeType: string | null | undefined): boolean => {
  const normalized = (mimeType ?? "").toLowerCase();
  return normalized.startsWith("image/") || normalized.includes("pdf");
};

const buildFinanceFileDownloadUrl = (fileId: number | null | undefined): string | null => {
  if (!Number.isInteger(fileId) || Number(fileId) <= 0) {
    return null;
  }
  return `/finance/files/${Number(fileId)}/download`;
};

const formatCurrencyLabel = (
  value: number | string | null | undefined,
  currencyCode: string | null | undefined,
): string => {
  if (value == null) {
    return "-";
  }
  const parsed = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(parsed)) {
    return "-";
  }
  const currency = (currencyCode ?? "USD").toUpperCase();
  return `${currency} ${parsed.toFixed(2)}`;
};

const resolveOpenBarMode = (productName: string | null | undefined): OpenBarMode => {
  const normalized = productName?.trim().toLowerCase() ?? "";
  if (normalized.includes("bottomless brunch")) {
    return "bottomlessBrunch";
  }
  if (normalized.includes("pub crawl")) {
    return "pubCrawl";
  }
  return "default";
};

const computeOpenBarTotal = (normal: number, cocktails: number, brunch: number, mode: OpenBarMode): number => {
  switch (mode) {
    case "pubCrawl":
      return normal + cocktails;
    case "bottomlessBrunch":
      return brunch;
    default:
      return normal + cocktails + brunch;
  }
};

const toEditableReport = (report: NightReport | null, directory?: Map<string, Venue>): EditableReport => {
  const resolveVenueId = (name: string, fallbackId?: number | null): number | null => {
    if (fallbackId != null) {
      return fallbackId;
    }
    if (!directory) {
      return null;
    }
    const normalized = name.trim().toLowerCase();
    if (!normalized) {
      return null;
    }
    const match = directory.get(normalized);
    return match?.id ?? null;
  };

  if (!report) {
    return {
      activityDate: dayjs().format(DATE_FORMAT),
      leaderId: null,
      notes: "",
      counterId: null,
      venues: [createEmptyVenue()],
    };
  }

  const sorted = (report.venues ?? [])
    .slice()
    .sort((a, b) => a.orderIndex - b.orderIndex)
    .map((venue, index) => ({
      tempKey: generateTempKey(),
      id: venue.id,
      venueId: resolveVenueId(venue.venueName ?? "", venue.venueId ?? null),
      venueName: venue.venueName ?? "",
      totalPeople: venue.totalPeople != null ? String(venue.totalPeople) : "",
      normalCount: index === OPEN_BAR_INDEX && venue.normalCount != null ? String(venue.normalCount) : "",
      cocktailsCount: index === OPEN_BAR_INDEX && venue.cocktailsCount != null ? String(venue.cocktailsCount) : "",
      brunchCount: index === OPEN_BAR_INDEX && venue.brunchCount != null ? String(venue.brunchCount) : "",
    }));

  return {
    activityDate: report.activityDate ?? dayjs().format(DATE_FORMAT),
    leaderId: report.leader?.id ?? null,
    notes: report.notes ?? "",
    counterId: report.counter?.id ?? null,
    venues: sorted.length > 0 ? sorted : [createEmptyVenue()],
  };
};

const normalizeNumber = (value: string, fallback: number | null = null): number | null => {
  if (!value && value !== "0") {
    return fallback;
  }
  const parsed = Number(value);
  if (Number.isNaN(parsed) || parsed < 0) {
    return fallback;
  }
  return parsed;
};

const formatFileSize = (bytes: number | null | undefined): string => {
  const numeric = Number(bytes);
  if (!Number.isFinite(numeric) || numeric <= 0) {
    return "0 B";
  }
  const units = ["B", "KB", "MB", "GB"];
  let unitIndex = 0;
  let value = numeric;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  const formatted = value % 1 === 0 ? value.toString() : value.toFixed(1);
  return `${formatted} ${units[unitIndex]}`;
};

const buildVenuePayload = (
  report: EditableReport,
  mode: OpenBarMode = "default",
  directory?: Map<string, Venue>,
): NightReportVenueInput[] =>
  report.venues.map((venue, index) => {
    const payload: NightReportVenueInput = {
      orderIndex: index + 1,
      venueName: venue.venueName.trim(),
      isOpenBar: index === OPEN_BAR_INDEX,
      totalPeople: 0,
    };
    if (index === OPEN_BAR_INDEX) {
      const normalValue = normalizeNumber(venue.normalCount, 0) ?? 0;
      const cocktailsValue = normalizeNumber(venue.cocktailsCount, 0) ?? 0;
      const brunchValue = normalizeNumber(venue.brunchCount, 0) ?? 0;
      payload.normalCount = normalValue;
      payload.cocktailsCount = cocktailsValue;
      payload.brunchCount = brunchValue;
      payload.totalPeople = computeOpenBarTotal(normalValue, cocktailsValue, brunchValue, mode);
    } else {
      payload.totalPeople = normalizeNumber(venue.totalPeople, 0) ?? 0;
    }
    const normalizedName = payload.venueName.toLowerCase();
    const directoryMatch = directory?.get(normalizedName);
    const resolvedVenueId = venue.venueId ?? directoryMatch?.id ?? null;
    if (resolvedVenueId != null) {
      payload.venueId = resolvedVenueId;
    }
    return payload;
  });

const formatUserFullName = (user: Partial<User> | StaffOption | undefined): string => {
  if (!user) {
    return "";
  }
  const full = (user as { fullName?: string }).fullName ?? "";
  if (full.trim()) {
    return full.trim();
  }
  const first = (user as { firstName?: string | null }).firstName ?? "";
  const last = (user as { lastName?: string | null }).lastName ?? "";
  const fallback = (user as Partial<User>).username ?? "";
  return `${first} ${last}`.trim() || fallback;
};

const formatNightReportOptionLabel = (report: NightReportSummary): string => {
  const segments = [
    dayjs(report.activityDate).format("MMM D, YYYY"),
    report.productName?.trim() || null,
    report.leaderName?.trim() || null,
  ].filter(Boolean);
  return segments.join(" - ");
};

const resolveErrorMessage = (error: unknown, fallback: string): string => {
  if (typeof error === "string" && error.trim()) {
    return error;
  }
  if (error instanceof Error && error.message.trim()) {
    return error.message;
  }
  return fallback;
};

